  1→import React, { useCallback, useEffect, useRef, useState } from "react";
  2→import "./myprofile.css";
  3→import { useAuth } from "../../Context/useAuth";
  4→import { Outlet, useLocation, useNavigate } from "react-router-dom";
  5→import Sidebar from "../SideBar/Sidebar";
  6→import { updateFontColor, updateProfileData } from "../../../API/Api";
  7→import { AnimatePresence } from "framer-motion";
  8→import { useQueryClient } from "@tanstack/react-query";
  9→import Editor from "../HomePage/Editor/Editor";
 10→import getCroppedImage from "../../utils/getCroppedImage";
 11→import extractDominantColors from "../../utils/extractDominantColors";
 12→import MobileNavlink from "../mobileNavLink/MobileNavLink";
 13→import MobileSidebarLink from "../MobileSidebarLink/MobileSidebarLink";
 14→import WriteJournalButton from "../WriteJournalButton/WriteJournalButton";
 15→import Loader from "../loadingComponent/BgLoader";
 16→import ProfileBackgroundPicker from "./components/ProfileBackgroundPicker";
 17→import ProfileEditModal from "./components/ProfileEditModal";
 18→import ProfileFontColorSelector from "./components/ProfileFontColorSelector";
 19→import ProfileHeroSection from "./components/ProfileHeroSection";
 20→import ProfileTabList from "./components/ProfileTabList";
 21→import { PROFILE_GRADIENTS } from "./constants/profileGradients";
 22→import { createProfileSidebarLinks } from "./constants/profileSidebarLinks";
 23→import { PROFILE_TABS } from "./constants/profileTabs";
 24→
 25→const MyProfile = () => {
 26→    const { user, session, isLoading, notifCount, loading } = useAuth();
 27→
 28→    const userData = user?.userData?.[0];
 29→
 30→    const [showMobileSideBar, setShowMobileSideBar] = useState(false);
 31→
 32→    const [showProfileEditor, setShowProfileEditor] = useState(false);
 33→    const [editImagePreview, setEditImagePreview] = useState("");
 34→    const [profileEditAvatar, setProfileEditAvatar] = useState(null);
 35→    const [profileEditName, setProfileEditName] = useState("");
 36→    const [profileEditBio, setProfileEditBio] = useState("");
 37→
 38→    const [showEditor, setShowEditor] = useState(false);
 39→    const [showBgPicker, setShowBgPicker] = useState(false);
 40→
 41→    const [imageSrc, setImageSrc] = useState(null);
 42→    const [crop, setCrop] = useState({ x: 0, y: 0 });
 43→    const [zoom, setZoom] = useState(1);
 44→    const [croppedAreaPixels, setCropAreaPixels] = useState(null);
 45→    const [gradientPicked, setGradientPicked] = useState(null);
 46→    const [croppedImage, setCroppedImage] = useState({});
 47→
 48→    const [showFontColorSelector, setShowFontColorSelector] = useState(false);
 49→    const [fontColor, setFontColor] = useState("");
 50→
 51→    const inputRef = useRef();
 52→    const bgInputRef = useRef();
 53→    const fontColorInputRef = useRef();
 54→
 55→    const [dominantColors, setDominantColors] = useState("#ffffffff");
 56→    const [secondaryColors, setSecondaryColors] = useState("#ffffffff");
 57→
 58→    const [isUpdatingFont, setIsUpdatingFont] = useState(false);
 59→    const [isUpdatingProfileConfig, setIsUpdatingProfileConfig] = useState(false);
 60→    const [isSavingProfile, setIsSavingProfile] = useState(false);
 61→
 62→    const navigate = useNavigate();
 63→    const navigatePath = (path) => {
 64→        return navigate(path);
 65→    };
 66→    const location = useLocation();
 67→
 68→    const queryClient = useQueryClient();
 69→
 70→    const links = createProfileSidebarLinks({
 71→        location,
 72→        navigatePath,
 73→        navigate,
 74→        notifCount,
 75→        setShowEditor,
 76→    });
 77→    const gradients = PROFILE_GRADIENTS;
 78→    const tablists = PROFILE_TABS;
 79→
 80→    useEffect(() => {
 81→        setCroppedImage(userData?.background || null);
 82→        setFontColor(userData?.profile_font_color || "");
 83→    }, [userData?.background, userData?.profile_font_color]);
 84→
 85→    const opendRichTextEditor = () => {
 86→        setShowEditor(true);
 87→    };
 88→
 89→    const handleClickOpenSidebar = () => {
 90→        setShowMobileSideBar(true);
 91→    };
 92→
 93→    const handleCloseSidebar = () => {
 94→        setShowMobileSideBar(false);
 95→    };
 96→
 97→    const handleClickEdit = (e) => {
 98→        e.stopPropagation();
 99→        setShowFontColorSelector(false);
100→        setEditImagePreview(userData?.image_url);
101→        setProfileEditName(userData?.name);
102→        setProfileEditBio(userData?.bio);
103→        setShowProfileEditor(true);
104→    };
105→
106→    const closeEditor = (e) => {
107→        e.stopPropagation();
108→        setEditImagePreview("");
109→        handleHideGradientPicker(e);
110→        setImageSrc(null);
111→        setProfileEditAvatar(null);
112→        setShowProfileEditor(false);
113→    };
114→
115→    const handleCloseRichTextEditor = useCallback(() => {
116→        setShowEditor(false);
117→    }, []);
118→
119→    const handleImageOnChange = (e) => {
120→        const file = e.target.files[0];
121→        setProfileEditAvatar(file);
122→        if (file) {
123→            setProfileEditAvatar(file);
124→            const reader = new FileReader();
125→            reader.onloadend = () => {
126→                setEditImagePreview(reader.result);
127→            };
128→
129→            reader.readAsDataURL(file);
130→        } else {
131→            setEditImagePreview("");
132→        }
133→    };
134→
135→    const insertImageFromFile = (e) => {
136→        e.stopPropagation();
137→        if (inputRef.current) {
138→            inputRef.current.click();
139→        }
140→    };
141→
142→    const handleShowGradientPicker = (e) => {
143→        e.stopPropagation();
144→        setShowBgPicker(true);
145→    };
146→
147→    const handleHideGradientPicker = (e) => {
148→        e.stopPropagation();
149→        setShowBgPicker(false);
150→        setCroppedImage(userData?.background);
151→        setImageSrc(null);
152→        setGradientPicked(null);
153→    };
154→
155→    const handleSaveProfileEdit = async () => {
156→        setIsSavingProfile(true);
157→        const data = {
158→            name: profileEditName,
159→            image: profileEditAvatar,
160→            bio: profileEditBio,
161→            profileBg: croppedImage,
162→            dominantColors: dominantColors,
163→            secondaryColors: secondaryColors,
164→        };
165→
166→        try {
167→            const formdata = new FormData();
168→            Object.entries(data).forEach(([key, value]) => {
169→                if (value === undefined || value === null) {
170→                    return;
171→                }
172→                if (typeof value === "object" && value !== null && !(value instanceof File)) {
173→                    formdata.append(key, JSON.stringify(value));
174→                    return;
175→                }
176→
177→                formdata.append(key, value);
178→            });
179→
180→            await updateProfileData(formdata, session?.access_token);
181→        } catch {
182→            throw new Error("error saving update");
183→        } finally {
184→            setIsSavingProfile(false);
185→            setProfileEditAvatar(null);
186→            queryClient.invalidateQueries({ queryKey: ["userData"] });
187→            setShowProfileEditor(false);
188→        }
189→    };
190→
191→    const handleSaveProfileConfig = async () => {
192→        try {
193→            setIsUpdatingProfileConfig(true);
194→            if (imageSrc) {
195→                const croppedImageUrl = await getCroppedImage(imageSrc, croppedAreaPixels, userData.id, session?.access_token);
196→                if (croppedImageUrl) {
197→                    setCroppedImage({
198→                        backgroundImage: `url(${croppedImageUrl?.url})`,
199→                        backgroundSize: "cover",
200→                        backgroundPosition: "center",
201→                        backgroundRepeat: "no-repeat",
202→                    });
203→                }
204→            } else if (gradientPicked) {
205→                setCroppedImage(gradientPicked);
206→            }
207→        } catch {
208→            throw new Error("error updating profile");
209→        } finally {
210→            setIsUpdatingProfileConfig(false);
211→            setGradientPicked(null);
212→            setImageSrc(null);
213→            setShowBgPicker(false);
214→            queryClient.invalidateQueries({ queryKey: ["userData"] });
215→        }
216→    };
217→
218→    const handleRemoveBgPreview = () => {
219→        setImageSrc(null);
220→    };
221→
222→    const handleSelectGradient = useCallback((gradient) => {
223→        setCroppedImage(null);
224→        setImageSrc(null);
225→        setGradientPicked(gradient);
226→    }, []);
227→
228→    const handleInsertBgImage = (e) => {
229→        e.stopPropagation();
230→        if (bgInputRef.current) {
231→            bgInputRef.current.value = "";
232→            bgInputRef.current.click();
233→        }
234→    };
235→
236→    const handleBgOnchange = (e) => {
237→        const file = e.target.files[0];
238→        if (file) {
239→            const reader = new FileReader();
240→            reader.onloadend = () => {
241→                const img = new Image();
242→                img.crossOrigin = "anonymous";
243→
244→                img.src = reader.result;
245→
246→                img.onload = () => {
247→                    const colors = extractDominantColors(img);
248→                    setDominantColors(colors.primary);
249→                    setSecondaryColors(colors.secondary);
250→                };
251→
252→                setImageSrc(reader.result);
253→            };
254→
255→            reader.readAsDataURL(file);
256→        } else {
257→            return setGradientPicked({});
258→        }
259→    };
260→
261→    const handleClickFontColorSelector = (e) => {
262→        e.stopPropagation();
263→        setShowFontColorSelector(true);
264→    };
265→
266→    const handleClickInputColor = () => {
267→        if (fontColorInputRef.current) {
268→            fontColorInputRef.current.click();
269→        }
270→    };
271→
272→    const handleClickSaveFontColor = async () => {
273→        setIsUpdatingFont(true);
274→        const formdata = new FormData();
275→        formdata.append("fontColor", fontColor);
276→        try {
277→            await updateFontColor(session?.access_token, formdata);
278→            queryClient.invalidateQueries({ queryKey: ["userData"] });
279→        } catch {
280→            throw new Error("error updating font");
281→        } finally {
282→            setIsUpdatingFont(false);
283→            setShowFontColorSelector(false);
284→        }
285→    };
286→
287→    const hancleClickCancelFontSelect = () => {
288→        setShowFontColorSelector(false);
289→        setFontColor("");
290→    };
291→
292→    useEffect(() => {
293→        if (!session && !loading) {
294→            return navigate("/login");
295→        }
296→    }, [session, loading, navigate]);
297→
298→    if (isLoading) {
299→        return <Loader />;
300→    }
301→
302→    return (
303→        <>
304→            <ProfileFontColorSelector
305→                show={showFontColorSelector}
306→                fontColor={fontColor}
307→                fontColorInputRef={fontColorInputRef}
308→                setFontColor={setFontColor}
309→                handleClickInputColor={handleClickInputColor}
310→                hancleClickCancelFontSelect={hancleClickCancelFontSelect}
311→                handleClickSaveFontColor={handleClickSaveFontColor}
312→                isUpdatingFont={isUpdatingFont}
313→            />
314→            <ProfileBackgroundPicker
315→                show={showBgPicker}
316→                handleBgOnchange={handleBgOnchange}
317→                bgInputRef={bgInputRef}
318→                gradients={gradients}
319→                handleSelectGradient={handleSelectGradient}
320→                handleInsertBgImage={handleInsertBgImage}
321→                imageSrc={imageSrc}
322→                crop={crop}
323→                zoom={zoom}
324→                setCrop={setCrop}
325→                setZoom={setZoom}
326→                setCropAreaPixels={setCropAreaPixels}
327→                handleRemoveBgPreview={handleRemoveBgPreview}
328→                handleHideGradientPicker={handleHideGradientPicker}
329→                handleSaveProfileConfig={handleSaveProfileConfig}
330→                isUpdatingProfileConfig={isUpdatingProfileConfig}
331→            />
332→            <AnimatePresence>
333→                <ProfileEditModal
334→                    key={"profile-edit-modal"}
335→                    showProfileEditor={showProfileEditor}
336→                    closeEditor={closeEditor}
337→                    croppedImage={croppedImage}
338→                    gradientPicked={gradientPicked}
339→                    insertImageFromFile={insertImageFromFile}
340→                    handleImageOnChange={handleImageOnChange}
341→                    inputRef={inputRef}
342→                    editImagePreview={editImagePreview}
343→                    userData={userData}
344→                    handleShowGradientPicker={handleShowGradientPicker}
345→                    profileEditName={profileEditName}
346→                    setProfileEditName={setProfileEditName}
347→                    profileEditBio={profileEditBio}
348→                    setProfileEditBio={setProfileEditBio}
349→                    handleSaveProfileEdit={handleSaveProfileEdit}
350→                    isSavingProfile={isSavingProfile}
351→                />
352→
353→                {showEditor && <Editor key={"main-editor"} onClose={handleCloseRichTextEditor} />}
354→
355→                <div
356→                    key={"profile-page-layout"}
357→                    className="profile-parent-container"
358→                    style={croppedImage ? { background: `linear-gradient(135deg, ${dominantColors}0%, ${secondaryColors} 100%)` } : gradientPicked}
359→                >
360→                    {gradientPicked && <div className="blurred-gradient-bg" style={gradientPicked} />}
361→
362→                    {croppedImage && <div style={croppedImage} className="blurred-img-bg" />}
363→
364→                    <div className="side-bar-holder-container">
365→                        <Sidebar links={links} />
366→                    </div>
367→
368→                    <div style={{ color: fontColor || userData?.profile_font_color }} className="profile-center-bar-container">
369→                        <ProfileHeroSection
370→                            userData={userData}
371→                            user={user}
372→                            fontColor={fontColor}
373→                            handleClickEdit={handleClickEdit}
374→                            handleClickFontColorSelector={handleClickFontColorSelector}
375→                            croppedImage={croppedImage}
376→                            gradientPicked={gradientPicked}
377→                        />
378→
379→                        <ProfileTabList tablists={tablists} navigate={navigate} location={location} />
380→
381→                        <Outlet />
382→                    </div>
383→
384→                    <div className="profile-sidebar-right-holder-container">{/* Log out */}</div>
385→
386→                    {showMobileSideBar && <MobileSidebarLink onclose={handleCloseSidebar} />}
387→
388→                    <MobileNavlink clickOpenSidebar={handleClickOpenSidebar} />
389→                    <WriteJournalButton onOpen={opendRichTextEditor} />
390→                </div>
391→            </AnimatePresence>
392→        </>
393→    );
394→};
395→
396→export default MyProfile;
